import difflib, re

def letters_only(s):
    return re.sub(r'[^ء-ي ]','', s)

def similarity_ratio(a,b):
    a=norm(a)
    b=norm(b)
    return difflib.SequenceMatcher(None, a, b).ratio()

def token_f1(a,b):
    a=set(norm(a).split())
    b=set(norm(b).split())
    if not a and not b:
        return 1.0
    prec=len(a & b)/len(a) if a else 0.0
    rec=len(a & b)/len(b) if b else 0.0
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

